import json
import re
from docx import Document

TEMPLATE = \"/root/offer_letter_template.docx\"
OUTPUT = \"/root/offer_letter_filled.docx\"
DATA_FILE = \"/root/employee_data.json\"


def replace_in_paragraph(paragraph, data):
    \"\"\"Replace all {{KEY}} placeholders in a paragraph, handling split runs.\"\"\"
    full = \"\".join(r.text for r in paragraph.runs)
    if \"{{\" not in full:
        return
    for key, value in data.items():
        placeholder = \"{{\" + key + \"}}\"
        if placeholder in full:
            full = full.replace(placeholder, str(value))
    # Redistribute: put all text in first run, clear the rest
    if paragraph.runs:
        paragraph.runs[0].text = full
        for r in paragraph.runs[1:]:
            r.text = \"\"


def handle_conditional(paragraph, data):
    \"\"\"Handle {{IF_RELOCATION}}...{{END_IF_RELOCATION}} in a single paragraph.\"\"\"
    full = \"\".join(r.text for r in paragraph.runs)
    if \"{{IF_RELOCATION}}\" not in full:
        return
    keep = data.get(\"RELOCATION_PACKAGE\", \"No\") == \"Yes\"
    if keep:
        # Strip markers, keep content
        full = full.replace(\"{{IF_RELOCATION}}\", \"\")
        full = full.replace(\"{{END_IF_RELOCATION}}\", \"\")
    else:
        # Remove entire content
        full = \"\"
    if paragraph.runs:
        paragraph.runs[0].text = full
        for r in paragraph.runs[1:]:
            r.text = \"\"


def process_cell(cell, data):
    \"\"\"Process a table cell, including nested tables.\"\"\"
    for para in cell.paragraphs:
        handle_conditional(para, data)
        replace_in_paragraph(para, data)
    for nested_table in cell.tables:
        for row in nested_table.rows:
            for c in row.cells:
                process_cell(c, data)


def main():
    with open(DATA_FILE) as f:
        data = json.load(f)

    doc = Document(TEMPLATE)

    # 1. Process main paragraphs (conditionals first, then placeholders)
    for para in doc.paragraphs:
        handle_conditional(para, data)
        replace_in_paragraph(para, data)

    # 2. Process tables (including nested)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                process_cell(cell, data)

    # 3. Process headers and footers
    for section in doc.sections:
        for para in section.header.paragraphs:
            handle_conditional(para, data)
            replace_in_paragraph(para, data)
        for para in section.footer.paragraphs:
            handle_conditional(para, data)
            replace_in_paragraph(para, data)
        # Header/footer tables if any
        for tbl in section.header.tables:
            for row in tbl.rows:
                for cell in row.cells:
                    process_cell(cell, data)
        for tbl in section.footer.tables:
            for row in tbl.rows:
                for cell in row.cells:
                    process_cell(cell, data)

    doc.save(OUTPUT)
    print(f\"Saved filled offer letter to {OUTPUT}\")


if __name__ == \"__main__\":
    main()
